using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the tools ---
var notebook = new Notebook();

List<AITool> tools =
[
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// --- Create the chat client (abstraction layer only – no direct SDK calls) ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create the agent via Microsoft Agent Framework ---
const string instructions = """
    You are a thorough research agent. Your goal is to research the given topic
    using your available tools.

    Follow this process:
    1. Search the web with 2-4 targeted queries to gather information from
       different angles on the topic.
    2. After each search, save the most important findings as notes using
       save_note. Each note should capture a distinct insight or fact.
    3. Once you have gathered enough notes (at least 3), retrieve them with
       get_notes and write a comprehensive summary of your research findings.

    Be concise but thorough. Focus on verifiable facts and key insights.
    """;

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
