 Console.WriteLine($"\n📖 Researching: {topic}\n");

 // --- Run the agent with streaming output ---
 var session = await agent.CreateSessionAsync(topic);

 await foreach (var update in agent.RunStreamingAsync(
     [
         new ChatMessage(ChatRole.System, instructions),
         new ChatMessage(ChatRole.User, $"Research this topic: {topic}"),
     ],
     session))
 {
     if (update.Text is { Length: > 0 } text)
     {
         Console.Write(text);
     }
 }

 // --- Print collected notes ---
 Console.WriteLine($"\n\n{new string('─', 50)}");
 Console.WriteLine("📝 Collected Research Notes:\n");

 var allNotes = notebook.AllNotes;
 if (allNotes.Count == 0)
 {
     Console.WriteLine("  (no notes were saved)");
 }
 else
 {
     for (var i = 0; i < allNotes.Count; i++)
     {
         Console.WriteLine($"  {i + 1}. {allNotes[i]}");
     }
 }

