 // ---------------------------------------------------------------------------
 // Tool: Notebook — stores and retrieves research notes in-memory.
 // ---------------------------------------------------------------------------
 sealed class Notebook
 {
     private readonly List<string> _notes = [];

     public IReadOnlyList<string> AllNotes => _notes;

     [Description("Save a research note capturing a key finding or insight.")]
     public string SaveNote([Description("The note text to save")] string note)
     {
         _notes.Add(note);
         Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
         return $"Note saved successfully. You now have {_notes.Count} note(s).";
     }

     [Description("Retrieve all research notes saved so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes have been saved yet.";

         return string.Join("\n", _notes.Select((n, i) => $"Note {i + 1}: {n}"));
     }
 }
